import json

civic_docs = json.load(open(var_functions.query_db:26, 'r'))
funding_data = var_functions.query_db:38

statuses = {}
for doc in civic_docs:
    text = doc.get('text', '')
    lines = text.split('\n')
    section = None
    for line in lines:
        line = line.strip()
        if 'Design' in line and ('Capital' in line or 'Disaster' in line):
            section = 'design'
        elif 'Construction' in line and ('Capital' in line or 'Disaster' in line):
            section = 'construction'
        elif 'Not Started' in line and ('Capital' in line or 'Disaster' in line):
            section = 'not_started'
        elif section and line and len(line) > 10 and not line.startswith('(') and 'Updates:' not in line and 'Schedule:' not in line and 'Page' not in line and 'Project Description:' not in line:
            base = line.split('(')[0].strip()
            if section == 'construction':
                statuses[base] = 'completed'
            else:
                statuses[base] = section

print('Status map entries:', len(statuses))

results = []
for rec in funding_data:
    name = rec['Project_Name']
    base = name.split('(')[0].strip()
    status = 'unknown'
    if base in statuses:
        status = statuses[base]
    else:
        for key, val in statuses.items():
            if base.lower() in key.lower() or key.lower() in base.lower():
                status = val
                break
    results.append([name, rec['Funding_Source'], int(rec['Amount']), status])

results.sort(key=lambda x: x[0])

output_lines = []
for name, source, amount, status in results:
    output_lines.append(f"Project: {name}")
    output_lines.append(f"Funding Source: {source}")
    output_lines.append(f"Amount: ${amount:,}")
    output_lines.append(f"Status: {status}")
    output_lines.append("-" * 70)

final_output = "\n".join(output_lines)
count = len(results)
total_amount = sum(r[2] for r in results)

result = {
    'count': count,
    'total_funding': total_amount,
    'output': final_output
}
print('__RESULT__:')
print(json.dumps(result))

